// src/pages/Internship.jsx
import React, { useEffect, useState } from "react";
import InternshipCard from "../components/InternshipCard";
import InternshipModal from "../components/InternshipModal";
import axios from "axios";
import "./Internship.css";

const Internship = () => {
  const [internships, setInternships] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [applications, setApplications] = useState([]);
  const [modalData, setModalData] = useState(null);
  const [filters, setFilters] = useState({ location: "", mode: "", category: "" });
  const user = JSON.parse(localStorage.getItem("user"));
  const token = localStorage.getItem("token");

  const fetchInternships = async () => {
    try {
      const res = await axios.get("/api/internships");
      setInternships(res.data);
      setFiltered(res.data);
    } catch (err) {
      console.error("Error fetching internships", err);
    }
  };

  const fetchApplications = async () => {
    if (user.role !== "Student") return;
    try {
      const res = await axios.get("/api/applications", {
        headers: { Authorization: `Bearer ${token}` },
      });
      setApplications(res.data);
    } catch (err) {
      console.error("Error fetching applications", err);
    }
  };

  const applyInternship = async (internshipId) => {
    try {
      await axios.post(
        "/api/applications",
        { internshipId },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      alert("Applied successfully!");
      fetchApplications();
    } catch (err) {
      alert(err.response?.data?.message || "Apply failed");
    }
  };

  const handleAddEdit = async (data) => {
    try {
      if (data._id) {
        await axios.put(`/api/internships/${data._id}`, data, {
          headers: { Authorization: `Bearer ${token}` },
        });
      } else {
        await axios.post("/api/internships", data, {
          headers: { Authorization: `Bearer ${token}` },
        });
      }
      setModalData(null);
      fetchInternships();
    } catch (err) {
      alert("Error saving internship");
    }
  };

  const handleDelete = async (id) => {
    try {
      await axios.delete(`/api/internships/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      fetchInternships();
    } catch (err) {
      alert("Delete failed");
    }
  };

  const getStatus = (internshipId) => {
    const app = applications.find((a) => a.internship === internshipId);
    return app ? app.status : "Not Applied";
  };

  const handleFilter = () => {
    const { location, mode, category } = filters;
    const filteredList = internships.filter((i) => {
      return (
        (!location || i.location.toLowerCase().includes(location.toLowerCase())) &&
        (!mode || i.mode.toLowerCase().includes(mode.toLowerCase())) &&
        (!category || i.category.toLowerCase().includes(category.toLowerCase()))
      );
    });
    setFiltered(filteredList);
  };

  useEffect(() => {
    fetchInternships();
    fetchApplications();
  }, []);

  useEffect(() => {
    handleFilter();
  }, [filters]);

  return (
    <div className="internship-page">
      <h2>Internship Opportunities</h2>

      <div className="filters">
        <input
          type="text"
          placeholder="Filter by Location"
          value={filters.location}
          onChange={(e) => setFilters({ ...filters, location: e.target.value })}
        />
        <input
          type="text"
          placeholder="Filter by Mode"
          value={filters.mode}
          onChange={(e) => setFilters({ ...filters, mode: e.target.value })}
        />
        <input
          type="text"
          placeholder="Filter by Category"
          value={filters.category}
          onChange={(e) => setFilters({ ...filters, category: e.target.value })}
        />
      </div>

      {(user.role === "Admin" || user.role === "HR") && (
        <button onClick={() => setModalData({})}>+ Add Internship</button>
      )}

      <div className="internship-list">
        {filtered.map((internship) => (
          <InternshipCard
            key={internship._id}
            internship={internship}
            userRole={user.role}
            onApply={applyInternship}
            onEdit={setModalData}
            onDelete={handleDelete}
            applicationStatus={getStatus(internship._id)}
          />
        ))}
      </div>

      {modalData && (
        <InternshipModal
          data={modalData}
          onClose={() => setModalData(null)}
          onSave={handleAddEdit}
        />
      )}
    </div>
  );
};

export default Internship;
